// GetApiAccount Returns the current user, as it would from login
//
// Does not return tokens for the user.
//
// Corresponds with GET /api/Account (the `GetApiAccount` operationId).
func (c *Client) GetApiAccount(ctx context.Context, reqEditors ...RequestEditorFn) (*http.Response, error) {
	req, err := NewGetApiAccountRequest(c.Server)
	if err != nil {
		return nil, err
	}
	req = req.WithContext(ctx)
	if err := c.applyEditors(ctx, req, reqEditors); err != nil {
		return nil, err
	}
	return c.Client.Do(req)
}

